<template>
  <!-- 左侧分类导航 -->
  <div class="sidebar">
    <el-menu ref="menuRef" :default-active="String(currentCategory)" active-text-color="#03e19b" background-color="#252525" text-color="#fff">
      <el-menu-item v-if="collectionStatus" index="-1" @click="collectionClick()">
        <span slot="title">我的收藏</span>
      </el-menu-item>
      <template v-for="item in categoryList">
        <el-menu-item class="first-category-class" :key="String(item.id)">
          <template slot="title">
            <span>{{ item.nameCn }}</span>
          </template>
        </el-menu-item>
        <el-submenu
          :class="{
            'parent-active': String(data.id) === String(currentCategoryParent) || String(data.id) === String(currentCategory)
          }"
          v-for="data in item.children"
          :index="String(data.id)"
          :key="data.id"
        >
          <template slot="title">
            <span @click="thirdCategoryIdClick(data)">{{ data.nameCn }}</span>
          </template>
          <el-menu-item-group v-for="child in data.children" :key="String(child.id)">
            <el-menu-item
              :class="{ 'child-active': String(child.id) === String(currentCategory) }"
              :index="String(child.id)"
              @click="fourCategoryIdClick(child)"
            >
              L{{ child.nameCn }}
            </el-menu-item>
          </el-menu-item-group>
        </el-submenu>
      </template>
    </el-menu>
  </div>
</template>

<script>
import { getLatestVersion, getCategoryList } from '@/api/main';
import { getPluginVersion } from '@/utils/cepspy';

export default {
  name: 'SlideLeft',
  props: {
    parentCategoryId: {
      type: String,
      default: null
    },
    collectionStatus: {
      type: Boolean,
      default: false
    }
  },
  data() {
    return {
      categoryList: [],
      currentCategory: '-1', // 默认选中收藏
      currentCategoryParent: null,
      queryParams: {
        firstCategoryId: null,
        categoryId: null,
        thirdCategoryId: null,
        fourCategoryId: null
      }
    };
  },
  created() {
    this.getConfig();
  },
  methods: {
    getConfig() {
      // 获取配置信息
      getLatestVersion().then((versionInfo) => {
        this.getCategories();
      });
    },
    collectionClick() {
      this.currentCategory = '-1'; // 设置当前分类为收藏
      this.$emit('handleCollectionList', null); // 通知父组件刷新用户信息
    },
    async getCategories() {
      try {
        const params = { parentId: this.parentCategoryId };
        Promise.all([getLatestVersion(), getCategoryList(params)]).then(([versionInfo, response]) => {
          let lasterVersion = versionInfo.data;
          let currentVersion = getPluginVersion();
          if (lasterVersion && currentVersion && lasterVersion === currentVersion) {
            this.categoryList = response.data.filter((item) => !item.nameCn.includes('更新提示'));
          } else {
            this.categoryList = response.data || [];
          }
          this.selectFirstItem();
        });
      } catch (error) {
        console.error('获取分类列表失败:', error);
      }
    },
    selectFirstItem() {
      if (!this.categoryList || !this.categoryList.length) return;
      const first = this.categoryList[0];
      if (!first.children || !first.children.length) return;
      const second = first.children[0];
      if (second.children && second.children.length) {
        // 有第三层，先展开二级 submenu，再选中三级第一项
        this.$nextTick(() => {
          this.$refs.menuRef && this.$refs.menuRef.open(String(second.id));
          this.fourCategoryIdClick(second.children[0]);
        });
      } else {
        this.thirdCategoryIdClick(second);
      }
    },
    async thirdCategoryIdClick(child) {
      this.currentCategory = child.id;
      this.currentCategoryParent = null; // 设置当前父级分类

      this.queryParams.categoryId = null;
      this.queryParams.thirdCategoryId = child.id;
      this.queryParams.fourCategoryId = null; // 重置四级分类
      await this.handleQuery();
    },
    async fourCategoryIdClick(child) {
      this.currentCategory = child.id;
      this.currentCategoryParent = child.parentId; // 设置当前父级分类

      this.queryParams.categoryId = null;
      this.queryParams.thirdCategoryId = null;
      this.queryParams.fourCategoryId = child.id;
      await this.handleQuery();
    },
    async handleQuery() {
      this.$emit('handleParams', this.queryParams); // 通知父组件刷新用户信息
    }
  }
};
</script>

